interface Point { x: number; y: number; }

const WIDTH = 1920;
const HEIGHT = 1080;
const SCALE_X = WIDTH / 900;
const SCALE_Y = HEIGHT / 600;

// Scale province label/army coordinates from 900x600 database space to 1920x1080 SVG space
const PROVINCE_COORDINATES_1080 = Object.entries(PROVINCE_COORDINATES).reduce(
  (acc, [id, coord]) => {
    acc[id] = {
      x: coord.x * SCALE_X,
      y: coord.y * SCALE_Y
    };
    return acc;
  },
  {} as Record<string, Point>
);


