interface MapProps {
  selectedProvinceId: string | null;
  onSelectProvince: (id: string | null) => void;
  selectedArmyId: string | null;
  onSelectArmy: (id: string | null) => void;
}

export const Map: React.FC<MapProps> = ({
  selectedProvinceId,
  onSelectProvince,
  selectedArmyId,
  onSelectArmy
}) => {
  const {
    provinces,
    countries,
    armies,
    battles,
    activePlayerTag,
    moveArmy
  } = useGameStore(
    useShallow((state) => ({
      provinces: state.provinces,
      countries: state.countries,
      armies: state.armies,
      battles: state.battles,
      activePlayerTag: state.activePlayerTag,
      moveArmy: state.moveArmy
    }))
  );

  // Savaş Sisi Görüş Hesaplama (Fog of War Vision Calculation)
  const playerProvinces = Object.values(provinces).filter(
    p => p.owner === activePlayerTag || p.controller === activePlayerTag
  );
  const playerArmyProvinces = Object.values(armies)
    .filter(a => a.owner === activePlayerTag && a.size > 0)
    .map(a => a.locationProvinceId);

  const visibleProvinceIds = new Set<string>();

  // 1. Oyuncunun kendi/işgal ettiği toprakları ekle
  playerProvinces.forEach(p => {
    visibleProvinceIds.add(p.id);
  });

  // 2. Oyuncunun ordularının olduğu toprakları ekle
  playerArmyProvinces.forEach(id => {
    visibleProvinceIds.add(id);
  });

  // 3. Casus ağı gücü %60 veya daha fazla olan ülkelerin topraklarını ekle
  const playerCountry = countries[activePlayerTag];
  const playerSpyNetworks = playerCountry?.spyNetworks || {};
  Object.entries(provinces).forEach(([id, p]) => {
    const spyStrength = playerSpyNetworks[p.owner] || 0;
    if (spyStrength >= 60) {
      visibleProvinceIds.add(id);
    }
  });

  const fogOfWar = true; // Savaş Sisi kalıcı olarak zorunlu



  // Pan and Zoom State
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const mapRef = useRef<HTMLDivElement>(null);

  // Mouse pan handlers
  const handleMouseDown = (e: MouseEvent) => {
    if ((e.target as HTMLElement).tagName === 'svg' || (e.target as HTMLElement).tagName === 'rect' || (e.target as HTMLElement).tagName === 'line') {
      setIsDragging(true);
      dragStart.current = { x: e.clientX - pan.x, y: e.clientY - pan.y };
    }
  };

  const handleMouseMove = (e: MouseEvent) => {
    if (!isDragging) return;
    setPan({
      x: e.clientX - dragStart.current.x,
      y: e.clientY - dragStart.current.y
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const newZoom = Math.min(3, Math.max(0.5, zoom + (e.deltaY < 0 ? 0.1 : -0.1)));
    setZoom(newZoom);
  };

  // Zoom helpers
  const zoomIn = () => setZoom(z => Math.min(3, z + 0.2));
  const zoomOut = () => setZoom(z => Math.max(0.5, z - 0.2));
  const resetMap = () => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  };

  // Calculate moving army coordinates
  const getArmyPosition = (army: Army) => {
    const startCoord = PROVINCE_COORDINATES_1080[army.locationProvinceId];
    if (!army.targetProvinceId) return startCoord || { x: 0, y: 0 };
    const endCoord = PROVINCE_COORDINATES_1080[army.targetProvinceId];
    if (!startCoord || !endCoord) return { x: 0, y: 0 };

    const progress = army.travelProgress / 100;
    return {
      x: startCoord.x + (endCoord.x - startCoord.x) * progress,
      y: startCoord.y + (endCoord.y - startCoord.y) * progress
    };
  };

  // Unique key adjacency connection renderer to avoid drawing lines twice
  const renderedConnections = new Set<string>();
  const connections: React.ReactNode[] = [];

  Object.entries(ADJACENCY_GRAPH).forEach(([provId, neighbors]) => {
    const start = PROVINCE_COORDINATES_1080[provId];
    if (!start) return;

    neighbors.forEach((neighborId) => {
      const pairKey = [provId, neighborId].sort().join('-');
      if (renderedConnections.has(pairKey)) return;
      renderedConnections.add(pairKey);

      const end = PROVINCE_COORDINATES_1080[neighborId];
      if (!end) return;

      const isLineVisible = !fogOfWar || (visibleProvinceIds.has(provId) || visibleProvinceIds.has(neighborId));

      connections.push(
        <line
          key={pairKey}
          x1={start.x}
          y1={start.y}
          x2={end.x}
          y2={end.y}
          stroke={isLineVisible ? "rgba(190, 150, 90, 0.4)" : "rgba(190, 150, 90, 0.08)"}
          strokeWidth="2"
          strokeDasharray="4 4"
        />
      );
    });
  });

  const handleProvinceClick = (provinceId: string) => {
    const province = provinces[provinceId];
    if (!province) return;

    // If an army is selected and belongs to the player, order it to move!
    if (selectedArmyId) {
      const selectedArmy = armies[selectedArmyId];
      if (selectedArmy && selectedArmy.owner === activePlayerTag && !selectedArmy.isRetreating) {
        if (selectedArmy.locationProvinceId === provinceId) {
          // Deselect or do nothing
          onSelectProvince(provinceId);
          onSelectArmy(null);
          return;
        }

        // Calculate path
        const path = findShortestPath(selectedArmy.locationProvinceId, provinceId, ADJACENCY_GRAPH);
        if (path.length > 0) {
          moveArmy(selectedArmyId, path, provinceId);
          onSelectArmy(null); // Deselect army after ordering move
          onSelectProvince(provinceId);
          return;
        }
      }
    }

    onSelectProvince(provinceId);
    onSelectArmy(null); // Clear army selection when province changes
  };

  const handleArmyClick = (e: React.MouseEvent, armyId: string) => {
    e.stopPropagation();
    const army = armies[armyId];
    if (army) {
      onSelectArmy(armyId);
      onSelectProvince(null); // Clear province selection when army is selected
    }
  };

  return (
    <div
      ref={mapRef}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      onWheel={handleWheel}
      style={{
        width: '100%',
        height: '100%',
        overflow: 'hidden',
        position: 'relative',
        cursor: isDragging ? 'grabbing' : 'grab',
        background: '#070a0f',
        backgroundImage: 'radial-gradient(circle, #0c1424 0%, #040608 100%)',
        boxShadow: 'inset 0 0 120px rgba(0, 0, 0, 0.95)'
      }}
    >
      {/* Zoom / Reset Controls Overlay */}
      <div style={{ position: 'absolute', bottom: '20px', left: '20px', display: 'flex', gap: '8px', zIndex: 10 }}>
        <button onClick={zoomIn} style={{ width: '36px', height: '36px', padding: 0 }}>+</button>
        <button onClick={zoomOut} style={{ width: '36px', height: '36px', padding: 0 }}>-</button>
        <button onClick={resetMap} style={{ height: '36px', fontSize: '0.8rem' }}>Reset Map</button>
      </div>

      <div
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
          transformOrigin: '0 0',
          transition: isDragging ? 'none' : 'transform 0.15s cubic-bezier(0.25, 0.8, 0.25, 1)',
          width: `${WIDTH}px`,
          height: `${HEIGHT}px`,
          position: 'absolute'
        }}
      >
        <svg width={WIDTH} height={HEIGHT} style={{ pointerEvents: 'auto' }}>
          {/* Custom Filters for old paper drop shadow effect */}
          <defs>
            <filter id="shadow" x="-20%" y="-20%" width="140%" height="140%">
              <feDropShadow dx="0" dy="4" stdDeviation="6" floodColor="#000" floodOpacity="0.75" />
            </filter>
            <filter id="glow" x="-20%" y="-20%" width="140%" height="140%">
              <feGaussianBlur stdDeviation="3.5" result="blur" />
              <feComposite in="SourceGraphic" in2="blur" operator="over" />
            </filter>
          </defs>

          {/* Adjacency Lines */}
          <g>{connections}</g>

          {/* Render Active Path for selected army */}
          {selectedArmyId && armies[selectedArmyId] && armies[selectedArmyId].path.length > 0 && (() => {
            const army = armies[selectedArmyId];
            const coords = [PROVINCE_COORDINATES_1080[army.locationProvinceId]];
            army.path.forEach(pId => {
              if (PROVINCE_COORDINATES_1080[pId]) coords.push(PROVINCE_COORDINATES_1080[pId]);
            });

            return (
              <g>
                {coords.map((c, idx) => {
                  if (idx === 0) return null;
                  const prev = coords[idx - 1];
                  return (
                    <line
                      key={`path-${idx}`}
                      x1={prev.x}
                      y1={prev.y}
                      x2={c.x}
                      y2={c.y}
                      stroke="var(--color-mil)"
                      strokeWidth="3.5"
                      strokeDasharray="6 4"
                      opacity="0.85"
                    />
                  );
                })}
              </g>
            );
          })()}

          {/* Province Fills & Interactivity */}
          <g>
            {/* Active Province Fills & Interactivity */}
            {Object.entries(provinces).map(([id, p]) => {
              const coord = PROVINCE_COORDINATES_1080[id];
              const pathD = PROVINCE_PATHS[id];
              
              if (!coord || !pathD) return null;

              const isSelected = selectedProvinceId === id;
              const isVisible = visibleProvinceIds.has(id);
              const ownerCountry = countries[p.owner];
              const color = ownerCountry ? ownerCountry.color : '#7f8c8d';

              return (
                <path
                  key={`cell-${id}`}
                  d={pathD}
                  fill={color}
                  fillOpacity={isVisible ? (isSelected ? 0.55 : 0.32) : 0.45}
                  stroke={isVisible ? (isSelected ? '#d4af37' : 'rgba(7, 9, 14, 0.45)') : 'rgba(5, 7, 10, 0.6)'}
                  strokeWidth={isSelected && isVisible ? '3.5' : '1.2'}
                  onClick={() => handleProvinceClick(id)}
                  filter={isSelected && isVisible ? 'url(#glow)' : undefined}
                  style={{
                    cursor: 'pointer',
                    transition: 'fill-opacity 0.2s ease, stroke-width 0.2s ease, filter 0.2s ease',
                    filter: isVisible ? undefined : 'brightness(0.3) saturate(0.55)'
                  }}
                />
              );
            })}
          </g>



          {/* Province Text Labels & Overlays (Unmasked) */}
          <g style={{ pointerEvents: 'none' }}>
            {Object.entries(provinces).map(([id, p]) => {
              const coord = PROVINCE_COORDINATES_1080[id];
              if (!coord) return null;

              const isVisible = visibleProvinceIds.has(id);
              const isOccupied = p.owner !== p.controller;
              const controllerCountry = countries[p.controller];

              return (
                <g key={`label-${id}`} transform={`translate(${coord.x}, ${coord.y})`}>
                  {/* Crown if Capital */}
                  {p.isCapital && isVisible && (
                    <polygon
                      points="-6,-16 6,-16 4,-12 -4,-12"
                      fill="#d4af37"
                      stroke="rgba(0,0,0,0.6)"
                      strokeWidth="0.8"
                    />
                  )}

                  {/* Province Name Label */}
                  <text
                    y="-2"
                    textAnchor="middle"
                    fill="#f5eedc"
                    fontWeight="700"
                    fontSize="9.5"
                    letterSpacing="1px"
                    opacity={isVisible ? 1 : 0.22}
                    style={{
                      fontFamily: 'var(--font-title)',
                      textShadow: isVisible ? '0 2px 4px rgba(0,0,0,0.95)' : 'none'
                    }}
                  >
                    {p.name.toUpperCase()}
                  </text>

                  {/* Development Number */}
                  {isVisible && (
                    <text
                      y="9"
                      textAnchor="middle"
                      fill="#a1a1aa"
                      fontWeight="600"
                      fontSize="8"
                      style={{ fontFamily: 'monospace', textShadow: '0 1.5px 3px rgba(0,0,0,0.95)' }}
                    >
                      {getProvinceDevelopment(p)}
                    </text>
                  )}

                  {/* Siege warning indicator */}
                  {isVisible && p.controller === p.owner && Object.values(armies).some(a => a.locationProvinceId === id && a.owner !== p.owner && a.size > 0) && (
                    <text
                      x="18"
                      y="4"
                      fill="var(--color-unrest)"
                      fontWeight="bold"
                      fontSize="10"
                      style={{ textShadow: '0 1px 2px #000' }}
                    >
                      ⚠️
                    </text>
                  )}

                  {/* Occupied Flag Indicator */}
                  {isVisible && isOccupied && (
                    <rect
                      x="-14"
                      y="12"
                      width="8"
                      height="5"
                      fill={controllerCountry?.color || '#e74c3c'}
                      stroke="#000"
                      strokeWidth="0.5"
                    />
                  )}
                </g>
              );
            })}
          </g>

          {/* Battles (Crossed Swords overlay) */}
          <g>
            {Object.values(battles).map((b) => {
              const coord = PROVINCE_COORDINATES_1080[b.provinceId];
              if (!coord) return null;

              const isVisible = visibleProvinceIds.has(b.provinceId);
              if (!isVisible) return null;

              return (
                <g
                  key={b.id}
                  transform={`translate(${coord.x}, ${coord.y - 30})`}
                  className="pulse-marker"
                  style={{ pointerEvents: 'none' }}
                >
                  <circle r="13" fill="#c0392b" stroke="var(--border-gold)" strokeWidth="1.5" filter="url(#shadow)" />
                  <text
                    y="3.5"
                    textAnchor="middle"
                    fill="#fff"
                    fontWeight="bold"
                    fontSize="13"
                  >
                    ⚔
                  </text>
                </g>
              );
            })}
          </g>
        </svg>

        {/* Army Banners (EU4 Style Flags) */}
        {Object.values(armies)
          .filter(a => a.size > 0 && (a.owner === activePlayerTag || visibleProvinceIds.has(a.locationProvinceId)))
          .map((a) => {
            const pos = getArmyPosition(a);
            const isSelected = selectedArmyId === a.id;
            const ownerCountry = countries[a.owner];

            return (
              <div
                key={a.id}
                onClick={(e) => handleArmyClick(e, a.id)}
                style={{
                  position: 'absolute',
                  left: `${pos.x - 22}px`,
                  top: `${pos.y - 42}px`,
                  background: 'linear-gradient(to bottom, #2a2016, #16100b)',
                  border: isSelected ? '2px solid #fff' : '1.5px solid var(--border-gold-dark)',
                  borderLeft: `4px solid ${ownerCountry?.color || '#a1a1aa'}`, // Flag pole style
                  borderRadius: '2px',
                  color: '#f3e5c8',
                  padding: '2px 5px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '4px',
                  fontSize: '0.75rem',
                  fontWeight: 'bold',
                  cursor: 'pointer',
                  zIndex: isSelected ? 110 : 80,
                  boxShadow: '0 3px 6px rgba(0,0,0,0.6)',
                  transition: 'border-color 0.15s ease, transform 0.15s ease',
                  fontFamily: 'monospace',
                  transform: isSelected ? 'scale(1.05)' : 'none'
                }}
              >
                <span>{(a.size / 1000).toFixed(1)}k</span>
                {a.general && <span style={{ fontSize: '0.65rem', color: 'var(--color-gold)' }}>★</span>}
              </div>
            );
          })}
      </div>
    </div>
  );
};
